// Total floats ~ 2 * (tileM * tileK + tileK * tileN + tileM * tileN)
static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN = 32;  // align to 32 floats (128 bytes)

static inline uint32_t CeilDiv(uint32_t a, uint32_t b) {
    return (a + b - 1) / b;
}

static inline uint32_t AlignDown(uint32_t x, uint32_t a) {
    return (x / a) * a;
}

static inline uint32_t compute_tileM(uint32_t M, uint32_t K, uint32_t N, uint32_t tileK, uint32_t tileN) {
    // max floats from UB: 2*(tileM*tileK + tileK*tileN + tileM*tileN) <= UB_BUDGET/4
    uint32_t max_floats = UB_BUDGET_BYTES / 4 / 2;  // divided by double buffer factor
    uint32_t numerator = max_floats - tileK * tileN;
    uint32_t denominator = tileK + tileN;
    if (denominator == 0) return 1;
    uint32_t tileM = numerator / denominator;
    tileM = AlignDown(tileM, ALIGN);
    if (tileM == 0) tileM = ALIGN;
    if (tileM > M) tileM = AlignDown(M, ALIGN);
    if (tileM == 0) tileM = M;
    return tileM;
}

